import './FormErrorMessage.scss';

import { Icon } from ':components/Icon';
import { Typography } from ':components/Typography';

import { classNames } from ':helpers/classnames';
import { Icons } from '@beeline/design-tokens/js/iconfont/icons';
import React from 'react';
import type { FormErrorMessageProps } from './FormErrorMessage.types';

export const FormErrorMessage = ({
	withIcon = false,
	className,
	children,
	dataTestId = 'FormErrorMessage',
	...props
}: FormErrorMessageProps) => {
	return (
		<span
			className={classNames('dsb_form-error-message', { 'dsb_form-error-message__with-icon': withIcon }, className)}
			data-testid={dataTestId}
			{...props}
		>
			{withIcon && (
				<Icon iconName={Icons.WarningCircled} size="small" className="dsb_form-error-message-icon" aria-hidden="true" />
			)}
			<Typography variant="body3" className="dsb_form-error-message-text">
				{children}
			</Typography>
		</span>
	);
};

FormErrorMessage.displayName = 'FormErrorMessage';
